/// <summary>
/// Falha imediata se o jogador receber QUALQUER dano (PlayerProgress.currentHearts
/// descer abaixo do valor registado ao iniciar o desafio) — base de desafios
/// "sem dano" (ex: Provação de Apolo, Tarefa #15).
/// </summary>
[System.Serializable]
public class FailCondition_PlayerDamaged : ChallengeFailCondition
{
    [System.NonSerialized] private int baselineHearts;

    public override void ResetState()
    {
        baselineHearts = PlayerProgress.Instance != null ? PlayerProgress.Instance.currentHearts : 0;
    }

    public override bool IsFailed() =>
        PlayerProgress.Instance != null && PlayerProgress.Instance.currentHearts < baselineHearts;
}

/// <summary>
/// Falha imediata se o jogador for derrotado (PlayerProgress.currentHearts &lt;= 0)
/// durante o desafio — usar em desafios de Sobrevivência/Defesa de NPC para
/// terminar o desafio com o ecrã "FALHOU" em vez de seguir o fluxo normal de
/// morte/checkpoint.
/// </summary>
[System.Serializable]
public class FailCondition_PlayerDefeated : ChallengeFailCondition
{
    public override bool IsFailed() =>
        PlayerProgress.Instance != null && PlayerProgress.Instance.currentHearts <= 0;
}
